package pe.org.camaracomercioica.protestos.util; import org.springframework.web.multipart.MultipartFile; import pe.org.camaracomercioica.protestos.exception.BadRequestException; import java.util.Set; public class UploadValidator { private final long maxBytes; public UploadValidator(long maxBytes){this.maxBytes=maxBytes;} public void validateDocument(MultipartFile f){validate(f,Set.of("application/pdf","image/png","image/jpeg"),Set.of("pdf","png","jpg","jpeg"));} public void validateExcel(MultipartFile f){validate(f,Set.of("application/vnd.openxmlformats-officedocument.spreadsheetml.sheet","application/vnd.ms-excel"),Set.of("xlsx","xls"));} private void validate(MultipartFile f,Set<String> types,Set<String> exts){String n=f.getOriginalFilename(); if(f.isEmpty()||n==null||n.contains("..")||n.contains("/")||n.contains("\\"))throw new BadRequestException("Archivo inválido"); String ext=n.substring(n.lastIndexOf('.')+1).toLowerCase(); if(f.getSize()>maxBytes||!types.contains(f.getContentType())||!exts.contains(ext))throw new BadRequestException("Tipo o tamaño de archivo no permitido");} }
